class AsyncHighPerformanceDataService:
    def __init__(self):
        self.processor = DataProcessor()

    async def ProcessData(self, request, context):
        response = DataResponse()
        # Run CPU-bound processing in executor
        loop = asyncio.get_event_loop()
        result = await loop.run_in_executor(
            None, 
            self.processor.process_single, 
            request.data
        )
        response.result = result
        response.processed_at = int(time.time() * 1000000)
        response.status = 'OK'
        return response

    async def BidirectionalStream(self, request_iterator, context):
        async for request in request_iterator:
            loop = asyncio.get_event_loop()
            processed = await loop.run_in_executor(
                None,
                self.processor.process_stream_chunk,
                request.chunk
            )
            
            response = StreamDataResponse()
            response.processed_chunk = processed
            response.chunk_id = request.chunk_id
            yield response


